import{_ as e,o as i,c as a,a3 as s}from"./chunks/framework.LBeL10WQ.js";const h=JSON.parse('{"title":"Integration & Sending","description":"","frontmatter":{"title":"Integration & Sending"},"headers":[],"relativePath":"en/publishers/display-email/integration.md","filePath":"en/publishers/display-email/integration.md"}'),o={name:"en/publishers/display-email/integration.md"};function n(d,t,r,l,c,p){return i(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="integration-and-broadcast" tabindex="-1">Integration and Broadcast <a class="header-anchor" href="#integration-and-broadcast" aria-label="Permalink to &quot;Integration and Broadcast&quot;">​</a></h1><p>The process is fast — just make sure you use the correct redirection link to get paid.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Receiving the visual</h3><p>The advertiser sends you their banner (JPG, PNG or GIF, max 150 KB).</p><ul><li>Verify that the format matches your placement (e.g., 600 × 150 px for a Leaderboard).</li><li>Check readability on mobile.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Retrieving the Tracked Link</h3><p>On <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>, open the <strong>&quot;Configuration and tracking&quot;</strong> tab of the campaign and copy the <strong>tracked link</strong> (format <code>https://gtinsi.de/…</code>).</p><p><em>Unlike the dedicated email, there is no open pixel to install. Only clicks are counted for this format.</em></p></div></div><div class="danger custom-block"><p class="custom-block-title">Tracked link mandatory</p><p><strong>Never</strong> use the advertiser&#39;s raw link. Without the <code>gtinsi.de</code> link, clicks are not counted and you will not be paid.</p></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Insertion into your router</h3><p>In your emailing tool (Mailchimp, Brevo, Klaviyo...):</p><ol><li>Insert the advertiser&#39;s image in the designated spot.</li><li>Add a link to this image.</li><li>Paste the tracked <code>gtinsi.de</code> link as the destination URL.</li></ol></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Proof Test &amp; Validation</h3><p>Send a test email to <code>benoit+news@getinside.fr</code> for validation. On the platform, click on <strong>&quot;Validate the campaign&quot;</strong> and wait for the advertiser&#39;s validation.</p></div></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Broadcast &amp; Final Validation</h3><p>Route the email to your base. Once the send is complete, return to the platform and click on <strong>&quot;Validate the broadcast&quot;</strong>.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Blocking Action — Validate broadcast</p><p>Without this click, the funds remain escrowed. This action triggers billing and the credit to your Wallet (available 30 days after the campaign ends).</p></div>',10)])])}const m=e(o,[["render",n]]);export{h as __pageData,m as default};
